import os
import json
import base64
import logging
from datetime import datetime, timezone

from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from cloudevents.http import CloudEvent

logging.basicConfig(level=logging.INFO)

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "file_events")


def _get_clients():
    storage_client = storage.Client(project=PROJECT_ID)
    firestore_client = firestore.Client(project=PROJECT_ID)
    publisher = pubsub_v1.PublisherClient()
    return storage_client, firestore_client, publisher


def _parse_event(event):
    if isinstance(event, CloudEvent):
        data = event.data or {}
    elif isinstance(event, dict):
        data = event.get("data", event)
    else:
        data = {}

    if "bucket" in data and "name" in data:
        return data

    if "data" in data and isinstance(data["data"], (bytes, str)):
        raw = data["data"]
        if isinstance(raw, str):
            raw = raw.encode("utf-8")
        try:
            decoded = base64.b64decode(raw)
            obj = json.loads(decoded.decode("utf-8"))
            if "bucket" in obj and "name" in obj:
                return obj
        except Exception:
            pass

    return data


def process_file(event, context=None):
    storage_client, firestore_client, publisher = _get_clients()
    event_data = _parse_event(event)

    bucket_name = event_data.get("bucket")
    object_name = event_data.get("name")
    generation = str(event_data.get("generation", ""))
    metageneration = str(event_data.get("metageneration", ""))
    content_type = event_data.get("contentType", "")
    size = int(event_data.get("size", 0) or 0)
    updated = event_data.get("updated", "")

    if not bucket_name or not object_name:
        logging.warning("Missing bucket or name in event")
        return "ignored"

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(object_name)
    try:
        blob.reload()
        content_type = content_type or blob.content_type or ""
        size = size or int(blob.size or 0)
        updated = updated or (blob.updated.isoformat() if blob.updated else "")
    except Exception as exc:
        logging.exception("Failed to load blob metadata: %s", exc)

    file_doc = {
        "bucket": bucket_name,
        "name": object_name,
        "generation": generation,
        "metageneration": metageneration,
        "content_type": content_type,
        "size": size,
        "updated": updated,
        "processed_at": datetime.now(timezone.utc).isoformat(),
        "source": "gcs",
    }

    doc_id = f"{bucket_name}:{object_name}:{generation or 'latest'}"
    firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id).set(file_doc, merge=True)

    if PUBSUB_TOPIC:
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        message = json.dumps(file_doc).encode("utf-8")
        publisher.publish(topic_path, message=message, bucket=bucket_name, name=object_name, generation=generation)

    logging.info("Processed file gs://%s/%s", bucket_name, object_name)
    return "ok"


def cloud_event_handler(cloudevent: CloudEvent):
    return process_file(cloudevent)


def background_handler(event, context):
    return process_file(event, context)